// ============================================================================
// LogoWidget - Geometric git branch icon
// ============================================================================

struct LogoWidget : Widget {
    float logo_size = Welcome::LOGO_SIZE;
    uint32_t color = Theme::ACCENT;

    LogoWidget() {
        preferred_width = logo_size;
        preferred_height = logo_size;
    }

    void measure(const LayoutConstraints& constraints) override {
        preferred_width = logo_size;
        preferred_height = logo_size;
        Widget::measure(constraints);
    }

    void render(RenderContext& ctx) override {
        float cx = rect.x + rect.width / 2.0f;
        float cy = rect.y + rect.height / 2.0f;
        float scale = logo_size / 40.0f;  // Scale from base 40px design

        ctx.brush->SetColor(color_from_argb(color));

        // Main trunk (vertical line)
        ctx.target->DrawLine(
            D2D1::Point2F(cx, cy - 14.0f * scale),
            D2D1::Point2F(cx, cy + 16.0f * scale),
            ctx.brush, 2.5f * scale);

        // Left branch
        ctx.target->DrawLine(
            D2D1::Point2F(cx - 14.0f * scale, cy - 20.0f * scale),
            D2D1::Point2F(cx, cy - 6.0f * scale),
            ctx.brush, 2.5f * scale);

        // Right branch
        ctx.target->DrawLine(
            D2D1::Point2F(cx + 14.0f * scale, cy - 20.0f * scale),
            D2D1::Point2F(cx, cy - 6.0f * scale),
            ctx.brush, 2.5f * scale);

        // Branch nodes (small circles)
        D2D1_ELLIPSE node_left = D2D1::Ellipse(
            D2D1::Point2F(cx - 14.0f * scale, cy - 20.0f * scale),
            4.0f * scale, 4.0f * scale);
        D2D1_ELLIPSE node_right = D2D1::Ellipse(
            D2D1::Point2F(cx + 14.0f * scale, cy - 20.0f * scale),
            4.0f * scale, 4.0f * scale);
        D2D1_ELLIPSE node_bottom = D2D1::Ellipse(
            D2D1::Point2F(cx, cy + 16.0f * scale),
            4.0f * scale, 4.0f * scale);

        ctx.target->FillEllipse(node_left, ctx.brush);
        ctx.target->FillEllipse(node_right, ctx.brush);
        ctx.target->FillEllipse(node_bottom, ctx.brush);
    }
};

// ============================================================================
// OutlineButton Widget - Button with outline style for welcome screen
// ============================================================================

struct OutlineButton : Widget {
    const wchar_t* text = L"";
    IDWriteTextFormat* text_format = nullptr;

    // Colors
    uint32_t border_color = Theme::ACCENT;
    uint32_t bg_hover = Theme::ACCENT;
    uint32_t text_normal = Theme::ACCENT;
    uint32_t text_hover = 0xFFFFFFFF;
    uint32_t text_disabled = Theme::TEXT_MUTED;
    uint32_t border_disabled = Theme::TEXT_MUTED;

    float corner_radius = Welcome::BUTTON_RADIUS;
    float border_width = 1.5f;

    // Callback
    void (*on_click)(OutlineButton* btn, void* user_data) = nullptr;
    void* user_data = nullptr;

    OutlineButton() {
        flags |= WidgetFlags::Focusable;
        preferred_width = Welcome::BUTTON_WIDTH;
        preferred_height = Welcome::BUTTON_HEIGHT;
        width_mode = SizeMode::Fixed;
        height_mode = SizeMode::Fixed;
    }

    void render(RenderContext& ctx) override {
        D2D1_RECT_F bg_rect = D2D1::RectF(rect.x, rect.y, rect.x + rect.width, rect.y + rect.height);
        D2D1_ROUNDED_RECT rounded = { bg_rect, corner_radius, corner_radius };

        bool enabled = (flags & WidgetFlags::Enabled) != 0;
        bool hovered = (flags & WidgetFlags::Hovered) != 0;

        IDWriteTextFormat* fmt = text_format ? text_format : g_text_format_button;

        if (!enabled) {
            // Disabled: muted border and text
            ctx.brush->SetColor(color_from_argb(border_disabled));
            ctx.target->DrawRoundedRectangle(rounded, ctx.brush, border_width);
            if (text && text[0] && fmt) {
                ctx.draw_text(text, wcslen(text), fmt, bg_rect, text_disabled);
            }
        } else if (hovered) {
            // Hovered: filled background with white text
            ctx.fill_rounded_rect(bg_rect, corner_radius, bg_hover);
            if (text && text[0] && fmt) {
                ctx.draw_text(text, wcslen(text), fmt, bg_rect, text_hover);
            }
        } else {
            // Normal: outline only with accent text
            ctx.brush->SetColor(color_from_argb(border_color));
            ctx.target->DrawRoundedRectangle(rounded, ctx.brush, border_width);
            if (text && text[0] && fmt) {
                ctx.draw_text(text, wcslen(text), fmt, bg_rect, text_normal);
            }
        }

        // Focus ring (only show when keyboard focused, not just mouse clicked)
        if (flags & WidgetFlags::KeyboardFocused) {
            D2D1_RECT_F focus_rect = D2D1::RectF(
                rect.x - 2, rect.y - 2,
                rect.x + rect.width + 2, rect.y + rect.height + 2);
            ctx.brush->SetColor(color_from_argb(Theme::ACCENT));
            D2D1_ROUNDED_RECT focus_rounded = { focus_rect, corner_radius + 2, corner_radius + 2 };
            ctx.target->DrawRoundedRectangle(focus_rounded, ctx.brush, 2.0f);
        }
    }

    bool on_mouse_down(float x, float y, int button) override {
        (void)x; (void)y; (void)button;
        return true;
    }

    bool on_mouse_up(float x, float y, int button) override {
        (void)x; (void)y; (void)button;
        if ((flags & WidgetFlags::Hovered) && (flags & WidgetFlags::Enabled)) {
            if (on_click) on_click(this, user_data);
        }
        return true;
    }

    bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
        (void)ctrl; (void)shift; (void)alt;
        if ((vk == VK_RETURN || vk == VK_SPACE) && (flags & WidgetFlags::Enabled)) {
            if (on_click) on_click(this, user_data);
            return true;
        }
        return false;
    }
};

// ============================================================================
// RecentRepoItemWidget - Individual recent repository item
// ============================================================================

struct RecentRepoItemWidget : Widget {
    wchar_t path[MAX_PATH] = {};
    wchar_t name[256] = {};
    int64_t last_opened = 0;
    int item_index = -1;

    // Callbacks
    void (*on_click)(RecentRepoItemWidget* item, void* user_data) = nullptr;
    void (*on_context_menu)(RecentRepoItemWidget* item, int screen_x, int screen_y, void* user_data) = nullptr;
    void* user_data = nullptr;

    RecentRepoItemWidget() {
        flags |= WidgetFlags::Focusable;
        preferred_height = Welcome::REPO_ITEM_HEIGHT;
        height_mode = SizeMode::Fixed;
    }

    void set_data(const wchar_t* repo_path, const wchar_t* repo_name, int64_t opened_time, int index) {
        wcscpy_s(path, repo_path);
        wcscpy_s(name, repo_name);
        last_opened = opened_time;
        item_index = index;
    }

    void render(RenderContext& ctx) override {
        bool hovered = (flags & WidgetFlags::Hovered) != 0;

        D2D1_RECT_F item_rect = D2D1::RectF(rect.x, rect.y, rect.x + rect.width, rect.y + rect.height);

        // Hover background
        if (hovered) {
            ctx.fill_rounded_rect(item_rect, Theme::CORNER_RADIUS, Theme::BG_HOVER);
        }

        // Focus ring (keyboard navigation only)
        if (flags & WidgetFlags::KeyboardFocused) {
            D2D1_RECT_F focus_rect = D2D1::RectF(
                rect.x + 2.0f, rect.y + 2.0f,
                rect.x + rect.width - 2.0f, rect.y + rect.height - 2.0f);
            ctx.brush->SetColor(color_from_argb(Theme::ACCENT));
            D2D1_ROUNDED_RECT rr = { focus_rect, Theme::CORNER_RADIUS, Theme::CORNER_RADIUS };
            ctx.target->DrawRoundedRectangle(rr, ctx.brush, 2.0f);
        }

        // Folder icon
        float icon_x = rect.x + Theme::PADDING;
        float icon_y = rect.y + rect.height / 2.0f;

        ctx.brush->SetColor(color_from_argb(Theme::TEXT_SECONDARY));

        // Folder shape (6 line segments)
        ctx.target->DrawLine(D2D1::Point2F(icon_x, icon_y - 6.0f), D2D1::Point2F(icon_x, icon_y + 6.0f), ctx.brush, 1.5f);
        ctx.target->DrawLine(D2D1::Point2F(icon_x, icon_y + 6.0f), D2D1::Point2F(icon_x + 16.0f, icon_y + 6.0f), ctx.brush, 1.5f);
        ctx.target->DrawLine(D2D1::Point2F(icon_x + 16.0f, icon_y + 6.0f), D2D1::Point2F(icon_x + 16.0f, icon_y - 4.0f), ctx.brush, 1.5f);
        ctx.target->DrawLine(D2D1::Point2F(icon_x + 16.0f, icon_y - 4.0f), D2D1::Point2F(icon_x + 8.0f, icon_y - 4.0f), ctx.brush, 1.5f);
        ctx.target->DrawLine(D2D1::Point2F(icon_x + 8.0f, icon_y - 4.0f), D2D1::Point2F(icon_x + 6.0f, icon_y - 6.0f), ctx.brush, 1.5f);
        ctx.target->DrawLine(D2D1::Point2F(icon_x + 6.0f, icon_y - 6.0f), D2D1::Point2F(icon_x, icon_y - 6.0f), ctx.brush, 1.5f);

        // Repo name
        D2D1_RECT_F name_rect = D2D1::RectF(
            rect.x + 36.0f, rect.y + 8.0f,
            rect.x + rect.width - 30.0f, rect.y + 28.0f);
        ctx.draw_text(name, wcslen(name), g_text_format_repo_name, name_rect, Theme::TEXT_PRIMARY);

        // Path and timestamp with truncation
        wchar_t time_str[64];
        format_relative_time(last_opened, time_str, 64);

        wchar_t path_line[512];
        swprintf_s(path_line, L"%s \xB7 %s", path, time_str);

        float path_width = rect.width - 66.0f;

        // Create text layout for truncation
        if (g_dwrite_factory && ctx.target) {
            IDWriteTextLayout* path_layout = nullptr;
            g_dwrite_factory->CreateTextLayout(
                path_line, (UINT32)wcslen(path_line),
                g_text_format_repo_path,
                path_width, 18.0f,
                &path_layout);

            if (path_layout && g_text_format_repo_path) {
                DWRITE_TRIMMING trimming = { DWRITE_TRIMMING_GRANULARITY_CHARACTER, 0, 0 };
                IDWriteInlineObject* ellipsis = nullptr;
                g_dwrite_factory->CreateEllipsisTrimmingSign(g_text_format_repo_path, &ellipsis);
                if (ellipsis) {
                    path_layout->SetTrimming(&trimming, ellipsis);
                    ellipsis->Release();
                }

                ctx.brush->SetColor(color_from_argb(Theme::TEXT_MUTED));
                ctx.target->DrawTextLayout(
                    D2D1::Point2F(rect.x + 36.0f, rect.y + 30.0f),
                    path_layout, ctx.brush);

                path_layout->Release();
            }
        }

        // Right chevron (on hover)
        if (hovered) {
            float chev_x = rect.x + rect.width - 20.0f;
            float chev_y = rect.y + rect.height / 2.0f;
            ctx.brush->SetColor(color_from_argb(Theme::TEXT_SECONDARY));
            ctx.target->DrawLine(
                D2D1::Point2F(chev_x, chev_y - 5.0f),
                D2D1::Point2F(chev_x + 5.0f, chev_y),
                ctx.brush, 1.5f);
            ctx.target->DrawLine(
                D2D1::Point2F(chev_x + 5.0f, chev_y),
                D2D1::Point2F(chev_x, chev_y + 5.0f),
                ctx.brush, 1.5f);
        }
    }

    bool on_mouse_down(float x, float y, int button) override {
        if (button == 1) {  // Right click - show context menu immediately
            if (on_context_menu) {
                // Convert to screen coordinates
                POINT pt = { static_cast<LONG>(rect.x + x), static_cast<LONG>(rect.y + y) };
                ClientToScreen(g_main_window, &pt);
                on_context_menu(this, pt.x, pt.y, user_data);
            }
        }
        return true;
    }

    bool on_mouse_up(float x, float y, int button) override {
        (void)x; (void)y;
        if (button == 0) {  // Left click - fire on mouse up (can be cancelled by dragging away)
            if ((flags & WidgetFlags::Hovered) && on_click) {
                on_click(this, user_data);
            }
        }
        return true;
    }

    bool on_key_down(int vk, bool ctrl, bool shift, bool alt) override {
        (void)ctrl; (void)shift; (void)alt;
        if (vk == VK_RETURN || vk == VK_SPACE) {
            if (on_click) {
                on_click(this, user_data);
            }
            return true;
        }
        return false;
    }
};

// ============================================================================
// RecentRepoListWidget - Container for recent repository items
// ============================================================================

struct RecentRepoListWidget : Widget {
    RecentRepoItemWidget* items[Welcome::MAX_RECENT_REPOS] = {};
    size_t item_count = 0;

    // Callback for when a repo is clicked
    void (*on_repo_clicked)(const wchar_t* path, void* user_data) = nullptr;
    void* user_data = nullptr;

    RecentRepoListWidget() {
        flags |= WidgetFlags::RendersOwnChildren;
        flags |= WidgetFlags::FocusGroup;
        nav_direction = NavDirection::Vertical;  // Up/Down arrows navigate items
    }

    void clear_items() {
        // Detach all children from widget tree to prevent ghost hover/click targets
        first_child = nullptr;
        for (size_t i = 0; i < item_count; i++) {
            if (items[i]) {
                items[i]->parent = nullptr;
                items[i]->next_sibling = nullptr;
                items[i]->prev_sibling = nullptr;
            }
            items[i] = nullptr;
        }
        item_count = 0;
    }

    void add_item(RecentRepoItemWidget* item) {
        if (item_count < Welcome::MAX_RECENT_REPOS) {
            items[item_count++] = item;
            widget_add_child(this, item);
        }
    }

    void measure(const LayoutConstraints& constraints) override {
        preferred_width = constraints.max_width;
        preferred_height = static_cast<float>(item_count) * Welcome::REPO_ITEM_HEIGHT;
        Widget::measure(constraints);
    }

    void layout() override {
        float y = rect.y;
        for (size_t i = 0; i < item_count; i++) {
            if (items[i]) {
                items[i]->rect.x = rect.x;
                items[i]->rect.y = y;
                items[i]->rect.width = rect.width;
                items[i]->rect.height = Welcome::REPO_ITEM_HEIGHT;
                y += Welcome::REPO_ITEM_HEIGHT;
            }
        }
    }

    void render(RenderContext& ctx) override {
        for (size_t i = 0; i < item_count; i++) {
            if (items[i] && items[i]->is_visible()) {
                items[i]->render(ctx);
            }
        }
    }

    // Note: Mouse event routing is handled by EventDispatcher traversing the child list.
    // No manual forwarding overrides needed - they had incorrect coordinate math.
};

// ============================================================================
// WelcomeScreenWidget - Root container for the welcome screen
// ============================================================================

struct WelcomeScreenWidget : Widget {
    // Child widgets
    LogoWidget* logo = nullptr;
    Label* title_label = nullptr;
    Label* subtitle_label = nullptr;
    OutlineButton* open_button = nullptr;
    OutlineButton* clone_button = nullptr;
    Label* error_label = nullptr;
    Label* recent_header = nullptr;
    Label* no_recent_label = nullptr;
    RecentRepoListWidget* recent_list = nullptr;

    // Tooltip state (for clone button)
    float tooltip_opacity = 0.0f;
    bool tooltip_visible = false;

    // Error state
    wchar_t error_message[256] = {};
    float error_timer = 0.0f;

    // Callbacks
    void (*on_open_repo)(WelcomeScreenWidget* widget, void* user_data) = nullptr;
    void (*on_repo_selected)(WelcomeScreenWidget* widget, const wchar_t* path, void* user_data) = nullptr;
    void* user_data = nullptr;

    WelcomeScreenWidget() {
        flags |= WidgetFlags::RendersOwnChildren;
        width_mode = SizeMode::Fill;
        height_mode = SizeMode::Fill;
    }

    void measure(const LayoutConstraints& constraints) override {
        rect.width = constraints.max_width;
        rect.height = constraints.max_height;
        Widget::measure(constraints);
    }

    void layout() override {
        // Calculate centered content layout
        float content_top = Config::TITLE_BAR_HEIGHT;
        float content_height = rect.height - content_top;

        float center_x = rect.width / 2.0f;
        float content_width = (rect.width < Welcome::CONTENT_MAX_WIDTH + 100)
            ? rect.width - 40.0f
            : Welcome::CONTENT_MAX_WIDTH;
        float content_left = center_x - content_width / 2.0f;

        // Vertical positions (start at ~18% from top)
        float start_y = content_top + content_height * 0.18f;

        float logo_y = start_y;
        float title_y = logo_y + Welcome::LOGO_SIZE + 16.0f;
        float subtitle_y = title_y + 36.0f;
        float buttons_y = subtitle_y + 24.0f + Welcome::SECTION_SPACING;
        float error_y = buttons_y + Welcome::BUTTON_HEIGHT + 12.0f;
        float recent_header_y = error_y + 24.0f + 16.0f;
        float recent_list_y = recent_header_y + 28.0f;

        // Button positions (centered)
        float total_buttons_width = Welcome::BUTTON_WIDTH * 2 + Welcome::BUTTON_SPACING;
        float open_btn_left = center_x - total_buttons_width / 2.0f;
        float clone_btn_left = open_btn_left + Welcome::BUTTON_WIDTH + Welcome::BUTTON_SPACING;

        // Position logo (centered)
        if (logo) {
            logo->rect.x = center_x - logo->logo_size / 2.0f;
            logo->rect.y = logo_y;
            logo->rect.width = logo->logo_size;
            logo->rect.height = logo->logo_size;
        }

        // Position title (centered)
        if (title_label) {
            title_label->rect.x = content_left;
            title_label->rect.y = title_y;
            title_label->rect.width = content_width;
            title_label->rect.height = 40.0f;
        }

        // Position subtitle (centered)
        if (subtitle_label) {
            subtitle_label->rect.x = content_left;
            subtitle_label->rect.y = subtitle_y;
            subtitle_label->rect.width = content_width;
            subtitle_label->rect.height = 24.0f;
        }

        // Position buttons
        if (open_button) {
            open_button->rect.x = open_btn_left;
            open_button->rect.y = buttons_y;
            open_button->rect.width = Welcome::BUTTON_WIDTH;
            open_button->rect.height = Welcome::BUTTON_HEIGHT;
        }

        if (clone_button) {
            clone_button->rect.x = clone_btn_left;
            clone_button->rect.y = buttons_y;
            clone_button->rect.width = Welcome::BUTTON_WIDTH;
            clone_button->rect.height = Welcome::BUTTON_HEIGHT;
        }

        // Position error label
        if (error_label) {
            error_label->rect.x = content_left;
            error_label->rect.y = error_y;
            error_label->rect.width = content_width;
            error_label->rect.height = 20.0f;
        }

        // Position recent header
        if (recent_header) {
            recent_header->rect.x = content_left;
            recent_header->rect.y = recent_header_y;
            recent_header->rect.width = content_width;
            recent_header->rect.height = 24.0f;
        }

        // Position "no recent" label
        if (no_recent_label) {
            no_recent_label->rect.x = content_left;
            no_recent_label->rect.y = recent_header_y + 20.0f;
            no_recent_label->rect.width = content_width;
            no_recent_label->rect.height = 24.0f;
        }

        // Position recent list
        if (recent_list) {
            recent_list->rect.x = content_left;
            recent_list->rect.y = recent_list_y;
            recent_list->rect.width = content_width;
            recent_list->rect.height = static_cast<float>(recent_list->item_count) * Welcome::REPO_ITEM_HEIGHT;
            recent_list->layout();
        }
    }

    void render(RenderContext& ctx) override {
        // Render children
        if (logo) logo->render(ctx);
        if (title_label) title_label->render(ctx);
        if (subtitle_label) subtitle_label->render(ctx);
        if (open_button) open_button->render(ctx);
        if (clone_button) clone_button->render(ctx);

        // Render error with fade (fade duration is 0.5 seconds)
        if (error_label && error_message[0] != L'\0') {
            float opacity = 1.0f;
            if (error_timer < 0.5f) {
                opacity = error_timer / 0.5f;
            }
            // Temporarily adjust error color opacity
            D2D1_COLOR_F err_color = color_from_argb(Theme::STATUS_DELETED);
            err_color.a = opacity;
            ctx.brush->SetColor(err_color);
            ctx.target->DrawText(
                error_message, (UINT32)wcslen(error_message),
                g_text_format_welcome_subtitle,
                D2D1::RectF(error_label->rect.x, error_label->rect.y,
                           error_label->rect.x + error_label->rect.width,
                           error_label->rect.y + error_label->rect.height),
                ctx.brush);
        }

        // Render recent section
        if (recent_list && recent_list->item_count > 0) {
            if (recent_header) recent_header->render(ctx);
            recent_list->render(ctx);
        } else if (no_recent_label) {
            no_recent_label->render(ctx);
        }

        // Render tooltip for clone button
        render_tooltip(ctx);
    }

    void render_tooltip(RenderContext& ctx) {
        if (tooltip_opacity <= 0.0f || !clone_button) return;

        const wchar_t* tooltip_text = L"Coming soon";
        float tooltip_padding = 8.0f;
        float tooltip_height = 24.0f;

        // Cache the tooltip width measurement — the text never changes, so
        // we only need to create the IDWriteTextLayout once instead of every
        // frame the tooltip fades.
        static float s_tooltip_width = 0.0f;
        if (s_tooltip_width == 0.0f && g_dwrite_factory) {
            IDWriteTextLayout* tooltip_layout = nullptr;
            g_dwrite_factory->CreateTextLayout(
                tooltip_text, (UINT32)wcslen(tooltip_text),
                g_text_format_repo_path,
                200.0f, tooltip_height,
                &tooltip_layout);
            if (tooltip_layout) {
                DWRITE_TEXT_METRICS metrics;
                tooltip_layout->GetMetrics(&metrics);
                s_tooltip_width = metrics.width + tooltip_padding * 2;
                tooltip_layout->Release();
            } else {
                s_tooltip_width = 80.0f;  // Fallback
            }
        }
        float tooltip_width = s_tooltip_width > 0.0f ? s_tooltip_width : 80.0f;

        // Position below clone button, centered
        float tooltip_x = clone_button->rect.x + (clone_button->rect.width - tooltip_width) / 2.0f;
        float tooltip_y = clone_button->rect.y + clone_button->rect.height + 8.0f;

        D2D1_ROUNDED_RECT tooltip_rect = D2D1::RoundedRect(
            D2D1::RectF(tooltip_x, tooltip_y, tooltip_x + tooltip_width, tooltip_y + tooltip_height),
            4.0f, 4.0f);

        // Background with opacity
        D2D1_COLOR_F bg_color = color_from_argb(Theme::BG_ELEVATED);
        bg_color.a = tooltip_opacity;
        ctx.brush->SetColor(bg_color);
        ctx.target->FillRoundedRectangle(tooltip_rect, ctx.brush);

        // Border with opacity
        D2D1_COLOR_F border_color = color_from_argb(Theme::BORDER);
        border_color.a = tooltip_opacity;
        ctx.brush->SetColor(border_color);
        ctx.target->DrawRoundedRectangle(tooltip_rect, ctx.brush, 1.0f);

        // Text with opacity
        D2D1_COLOR_F text_color = color_from_argb(Theme::TEXT_SECONDARY);
        text_color.a = tooltip_opacity;
        ctx.brush->SetColor(text_color);

        // Use cached tooltip format (created in platform.cpp init)
        if (g_text_format_tooltip) {
            ctx.target->DrawText(
                tooltip_text, (UINT32)wcslen(tooltip_text),
                g_text_format_tooltip,
                D2D1::RectF(tooltip_x, tooltip_y, tooltip_x + tooltip_width, tooltip_y + tooltip_height),
                ctx.brush);
        }
    }

    void set_error(const wchar_t* message) {
        wcscpy_s(error_message, message);
        error_timer = 4.0f;  // ERROR_DISPLAY_DURATION
        set_dirty();
    }

    void clear_error() {
        error_message[0] = L'\0';
        error_timer = 0.0f;
    }

    void update_tooltip_animation(float dt) {
        constexpr float FADE_SPEED = 6.0f;  // Matches TOOLTIP_FADE_SPEED in platform.cpp
        if (tooltip_visible && tooltip_opacity < 1.0f) {
            tooltip_opacity += FADE_SPEED * dt;
            if (tooltip_opacity > 1.0f) tooltip_opacity = 1.0f;
            set_dirty();
        } else if (!tooltip_visible && tooltip_opacity > 0.0f) {
            tooltip_opacity -= FADE_SPEED * dt;
            if (tooltip_opacity < 0.0f) tooltip_opacity = 0.0f;
            set_dirty();
        }
    }

    void update_error_animation(float dt) {
        if (error_timer > 0.0f) {
            error_timer -= dt;
            if (error_timer <= 0.0f) {
                clear_error();
            }
            set_dirty();
        }
    }
};

// Global state (defined here, used by platform.cpp)
static WelcomeScreenWidget* g_welcome_screen = nullptr;
static WidgetTree g_welcome_tree = {};
static EventDispatcher g_welcome_dispatcher = {};
